diff --git a/include/nlohmann/detail/hash.hpp b/include/nlohmann/detail/hash.hpp
index 61b3469..7e33f49 100644
--- a/include/nlohmann/detail/hash.hpp
+++ b/include/nlohmann/detail/hash.hpp
@@ -90,7 +90,15 @@ std::size_t hash(const BasicJsonType& j)

         case BasicJsonType::value_t::number_integer:
         {
-            const auto h = std::hash<number_integer_t> {}(j.template get<number_integer_t>());
+            const auto v = j.template get<number_integer_t>();
+            // normalize non-negative integers to the unsigned hash path
+            // so that json(1) and json(1u) produce the same hash
+            if (v >= 0)
+            {
+                const auto h = std::hash<number_unsigned_t> {}(static_cast<number_unsigned_t>(v));
+                return combine(static_cast<std::size_t>(BasicJsonType::value_t::number_unsigned), h);
+            }
+            const auto h = std::hash<number_integer_t> {}(v);
             return combine(type, h);
         }
